svg.script:
var BASE = 'https://statevec.com';
var SVG_NS = 'http://www.w3.org/2000/svg';

// Shared secrets
var STATE_SECRET  = 'mpcr:ai:state';
var STATE_HASH    = '2cb87f5f6c4c76da45361c4f934bee8e3d2ed29f0439fc35fbc1ae1727059be9';
var CHECKIN_SECRET = 'mpcr:ai:checkins';
var CHECKIN_HASH   = 'a0c0e74f772b453b6e0352781490c9ac4dfdc781af90b4b3f24b667557c1d4e1';
var VOTES_SECRET  = 'mpcr:ai:votes';
var VOTES_HASH    = '802e1abbe632e0612827bb2a79e8bc892a90e1b6188550cc587d0e3139763a10';
var Q_SECRET      = 'mpcr:ai:questions';
var Q_HASH        = '02039b6bc9f648e1ddb26a3b3d1c192c210f68fc624ad875ea2c45974f855dfc';
var C_SECRET      = 'mpcr:ai:comments';
var C_HASH        = 'f28f9c8c5d9344c36a685ebc3817b445b16d76ae1eea257514362d953a36e2e6';

// Tensions data
var TENSIONS = [
  { id: 'tension0', left: 'Cognitive offloading', right: 'Deep learning', title: 'T1: Cognitive offloading vs. deep learning' },
  { id: 'tension1', left: 'Personalization', right: 'Belonging', title: 'T2: Personalization vs. belonging' },
  { id: 'tension2', left: 'Assistance', right: 'Authorship', title: 'T3: Assistance vs. authorship' },
  { id: 'tension3', left: 'Innovation', right: 'Governance', title: 'T4: Innovation vs. governance' }
];

// State
var myId = '';
var myName = '';
var myRole = '';
var myTable = 0;
var selectedRole = '';
var selectedTable = 0;
var currentTension = 0;
var currentPhase = 'waiting';
var votingOpen = true;
var myVote = 0;
var isAnonymous = true;

// DOM refs
var checkinMode = document.getElementById('checkinMode');
var participateMode = document.getElementById('participateMode');
var nameInput = document.getElementById('nameInput');
var joinBtn = document.getElementById('joinBtn');
var joinMsg = document.getElementById('joinMsg');
var tensionTitle = document.getElementById('tensionTitle');
var tensionPoles = document.getElementById('tensionPoles');
var phaseLabel = document.getElementById('phaseLabel');
var connDot = document.getElementById('connDot');
var voteConfirm = document.getElementById('voteConfirm');
var voteClosedLabel = document.getElementById('voteClosedLabel');
var waitingMsg = document.getElementById('waitingMsg');
var questionInput = document.getElementById('questionInput');
var askBtn = document.getElementById('askBtn');
var questionList = document.getElementById('questionList');
var commentInput = document.getElementById('commentInput');
var postBtn = document.getElementById('postBtn');
var commentList = document.getElementById('commentList');
var anonToggle = document.getElementById('anonToggle');
var anonLabel = document.getElementById('anonLabel');
var footerParticipants = document.getElementById('footerParticipants');
var poleLeftLabel = document.getElementById('poleLeftLabel');
var poleLeftLabel2 = document.getElementById('poleLeftLabel2');
var poleRightLabel = document.getElementById('poleRightLabel');
var poleRightLabel2 = document.getElementById('poleRightLabel2');
var discussPrompt = document.getElementById('discussPrompt');
var commentThrottled = false;

// ============ UTILITY ============
function genId() {
  return 'u' + Math.random().toString(36).substring(2, 10) + Date.now().toString(36);
}

function patchMerge(secret, val) {
  return fetch(BASE + '/v', {
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ key: secret, op: 'merge', val: val })
  });
}

function readHash(hash) {
  return fetch(BASE + '/v/' + hash).then(function(r) {
    if (r.ok) return r.json();
    return null;
  });
}

// ============ CHECK-IN MODE ============
// Role selection
var roleButtons = ['Educator', 'Researcher', 'Policymaker', 'Student', 'Other'];
roleButtons.forEach(function(role) {
  var btn = document.getElementById('role' + role);
  btn.addEventListener('click', function() {
    selectedRole = role;
    roleButtons.forEach(function(r) {
      var b = document.getElementById('role' + r);
      var t = document.getElementById('role' + r + 'Txt');
      if (r === role) {
        b.setAttribute('fill', '#c9a227');
        b.setAttribute('stroke', '#c9a227');
        t.setAttribute('fill', '#0a0e1a');
      } else {
        b.setAttribute('fill', '#111827');
        b.setAttribute('stroke', '#1e293b');
        t.setAttribute('fill', '#94a3b8');
      }
    });
  });
});

// Table selection
var tblBtns = document.querySelectorAll('.tblBtn');
var tblTxts = document.querySelectorAll('.tblTxt');
for (var ti = 0; ti < tblBtns.length; ti++) {
  (function(idx) {
    tblBtns[idx].addEventListener('click', function() {
      selectedTable = idx + 1;
      for (var j = 0; j < tblBtns.length; j++) {
        if (j === idx) {
          tblBtns[j].setAttribute('fill', '#c9a227');
          tblBtns[j].setAttribute('stroke', '#c9a227');
          tblTxts[j].setAttribute('fill', '#0a0e1a');
        } else {
          tblBtns[j].setAttribute('fill', '#111827');
          tblBtns[j].setAttribute('stroke', '#1e293b');
          tblTxts[j].setAttribute('fill', '#94a3b8');
        }
      }
    });
  })(ti);
}

// Join handler
joinBtn.addEventListener('click', function() {
  var name = nameInput.value.trim();
  if (!name) { joinMsg.textContent = 'Please enter your name'; return; }
  if (!selectedRole) { joinMsg.textContent = 'Please select a role'; return; }
  if (!selectedTable) { joinMsg.textContent = 'Please select a table'; return; }

  myName = name;
  myRole = selectedRole;
  myTable = selectedTable;
  myId = genId();

  // Save to localStorage
  try {
    localStorage.setItem('mpcr_ai_id', myId);
    localStorage.setItem('mpcr_ai_name', myName);
    localStorage.setItem('mpcr_ai_role', myRole);
    localStorage.setItem('mpcr_ai_table', String(myTable));
  } catch(e) {}

  // Write checkin
  var checkinData = {};
  checkinData[myId] = { name: myName, role: myRole, table: myTable, t: Date.now() };
  patchMerge(CHECKIN_SECRET, checkinData).then(function() {
    switchToParticipate();
  }).catch(function() {
    switchToParticipate();
  });
});

function switchToParticipate() {
  checkinMode.setAttribute('display', 'none');
  participateMode.setAttribute('display', 'inline');
  pollAll();
}

// ============ CHECK EXISTING SESSION ============
function checkExistingSession() {
  try {
    var id = localStorage.getItem('mpcr_ai_id');
    var name = localStorage.getItem('mpcr_ai_name');
    var role = localStorage.getItem('mpcr_ai_role');
    var table = localStorage.getItem('mpcr_ai_table');
    if (id && name && role && table) {
      myId = id;
      myName = name;
      myRole = role;
      myTable = parseInt(table);
      switchToParticipate();
      return true;
    }
  } catch(e) {}
  return false;
}

// ============ PARTICIPATE MODE ============

// Vote circles
for (var vi = 1; vi <= 5; vi++) {
  (function(val) {
    var circle = document.getElementById('vote' + val);
    circle.addEventListener('click', function() {
      if (!votingOpen) return;
      myVote = val;
      castVote(val);
      updateVoteDisplay();
    });
  })(vi);
}

function updateVoteDisplay() {
  for (var v = 1; v <= 5; v++) {
    var c = document.getElementById('vote' + v);
    var t = document.getElementById('vote' + v + 'Txt');
    if (v === myVote) {
      c.setAttribute('fill', '#c9a227');
      c.setAttribute('stroke', '#c9a227');
      t.setAttribute('fill', '#0a0e1a');
    } else {
      c.setAttribute('fill', votingOpen ? '#1e293b' : '#0a0e1a');
      c.setAttribute('stroke', votingOpen ? '#94a3b8' : '#1e293b');
      t.setAttribute('fill', votingOpen ? '#94a3b8' : '#1e293b');
    }
  }
  if (myVote > 0) {
    voteConfirm.setAttribute('display', 'inline');
    waitingMsg.setAttribute('display', 'none');
    discussPrompt.setAttribute('display', 'none');
  }
  if (!votingOpen) {
    voteClosedLabel.setAttribute('display', 'inline');
    if (currentPhase === 'tension') {
      discussPrompt.setAttribute('display', 'inline');
      voteConfirm.setAttribute('display', 'none');
    }
  } else {
    voteClosedLabel.setAttribute('display', 'none');
    discussPrompt.setAttribute('display', 'none');
  }
}

function castVote(val) {
  var voteKey = TENSIONS[currentTension].id + ':' + myId;
  var voteData = {};
  voteData[voteKey] = val;
  patchMerge(VOTES_SECRET, voteData).then(function() {
    connDot.setAttribute('fill', '#22c55e');
  }).catch(function() {
    connDot.setAttribute('fill', '#ef4444');
  });
}

// Enter key support
questionInput.addEventListener('keydown', function(e) { if (e.key === 'Enter') askBtn.dispatchEvent(new Event('click')); });
commentInput.addEventListener('keydown', function(e) { if (e.key === 'Enter') postBtn.dispatchEvent(new Event('click')); });

// Ask question
var questionThrottled = false;
askBtn.addEventListener('click', function() {
  var text = questionInput.value.trim();
  if (!text || questionThrottled) return;
  var qId = 'q' + Date.now().toString(36) + Math.random().toString(36).substring(2, 6);
  var qData = {};
  qData[qId] = { text: text, author: myName, table: myTable, tension: currentTension, votes: 0, voters: {}, t: Date.now() };
  questionThrottled = true;
  askBtn.setAttribute('fill', '#1e293b');
  patchMerge(Q_SECRET, qData).then(function() {
    questionInput.value = '';
    connDot.setAttribute('fill', '#22c55e');
  }).catch(function() {
    connDot.setAttribute('fill', '#ef4444');
  });
  setTimeout(function() { questionThrottled = false; askBtn.setAttribute('fill', '#3b82f6'); }, 3000);
});

// Post comment
postBtn.addEventListener('click', function() {
  var text = commentInput.value.trim();
  if (!text || commentThrottled) return;
  var cId = 'c' + Date.now().toString(36) + Math.random().toString(36).substring(2, 6);
  var cData = {};
  var authorName = isAnonymous ? 'Anonymous' : myName;
  cData[cId] = { text: text, author: authorName, table: myTable, tension: currentTension, t: Date.now() };
  commentThrottled = true;
  postBtn.setAttribute('fill', '#1e293b');
  patchMerge(C_SECRET, cData).then(function() {
    commentInput.value = '';
    connDot.setAttribute('fill', '#22c55e');
  }).catch(function() {
    connDot.setAttribute('fill', '#ef4444');
  });
  setTimeout(function() {
    commentThrottled = false;
    postBtn.setAttribute('fill', '#3b82f6');
  }, 5000);
});

// Anonymous toggle
anonToggle.addEventListener('click', function() {
  isAnonymous = !isAnonymous;
  if (isAnonymous) {
    anonToggle.setAttribute('stroke', '#c9a227');
    anonLabel.textContent = 'Anonymous';
    anonLabel.setAttribute('fill', '#c9a227');
  } else {
    anonToggle.setAttribute('stroke', '#3b82f6');
    anonLabel.textContent = myName;
    anonLabel.setAttribute('fill', '#3b82f6');
  }
});

// ============ RENDERING ============
function renderQuestions(data) {
  while (questionList.firstChild) questionList.removeChild(questionList.firstChild);
  if (!data) return;

  // Convert to array and sort by upvotes desc
  // Upvotes stored as flat keys: 'upvote:qId:userId' = true
  var questions = [];
  var keys = Object.keys(data);
  for (var i = 0; i < keys.length; i++) {
    var q = data[keys[i]];
    if (q && q.text && q.tension === currentTension) {
      q._id = keys[i];
      // Count upvotes from flat 'upvote:qId:*' keys
      var upvotes = 0;
      var myUpvoted = false;
      var upPrefix = 'upvote:' + keys[i] + ':';
      for (var j = 0; j < keys.length; j++) {
        if (keys[j].indexOf(upPrefix) === 0 && data[keys[j]]) {
          upvotes++;
          if (keys[j] === upPrefix + myId) myUpvoted = true;
        }
      }
      q._upvotes = upvotes;
      q._myUpvoted = myUpvoted;
      questions.push(q);
    }
  }
  questions.sort(function(a, b) { return b._upvotes - a._upvotes; });

  // Show top 3
  var top = questions.slice(0, 3);
  for (var j = 0; j < top.length; j++) {
    var q2 = top[j];
    var yy = 268 + j * 38;

    // Upvote button
    var upBtn = document.createElementNS(SVG_NS, 'rect');
    upBtn.setAttribute('x', '20');
    upBtn.setAttribute('y', yy);
    upBtn.setAttribute('width', '32');
    upBtn.setAttribute('height', '28');
    upBtn.setAttribute('rx', '4');
    upBtn.setAttribute('fill', q2._myUpvoted ? '#c9a227' : '#1e293b');
    upBtn.setAttribute('style', 'cursor:pointer');
    upBtn.setAttribute('data-qid', q2._id);
    upBtn.addEventListener('click', function() {
      upvoteQuestion(this.getAttribute('data-qid'));
    });
    questionList.appendChild(upBtn);

    var upCount = document.createElementNS(SVG_NS, 'text');
    upCount.setAttribute('x', '36');
    upCount.setAttribute('y', yy + 12);
    upCount.setAttribute('font-family', 'monospace');
    upCount.setAttribute('font-size', '9');
    upCount.setAttribute('fill', q2._myUpvoted ? '#0a0e1a' : '#f1f5f9');
    upCount.setAttribute('text-anchor', 'middle');
    upCount.setAttribute('style', 'pointer-events:none');
    upCount.textContent = '\u25B2';
    questionList.appendChild(upCount);

    var upNum = document.createElementNS(SVG_NS, 'text');
    upNum.setAttribute('x', '36');
    upNum.setAttribute('y', yy + 24);
    upNum.setAttribute('font-family', 'monospace');
    upNum.setAttribute('font-size', '9');
    upNum.setAttribute('fill', q2._myUpvoted ? '#0a0e1a' : '#94a3b8');
    upNum.setAttribute('text-anchor', 'middle');
    upNum.setAttribute('style', 'pointer-events:none');
    upNum.textContent = String(q2._upvotes);
    questionList.appendChild(upNum);

    // Question text
    var qText = document.createElementNS(SVG_NS, 'text');
    qText.setAttribute('x', '60');
    qText.setAttribute('y', yy + 13);
    qText.setAttribute('font-family', 'monospace');
    qText.setAttribute('font-size', '10');
    qText.setAttribute('fill', '#f1f5f9');
    var truncated = q2.text.length > 32 ? q2.text.substring(0, 32) + '...' : q2.text;
    qText.textContent = truncated;
    questionList.appendChild(qText);

    // Author
    var qAuthor = document.createElementNS(SVG_NS, 'text');
    qAuthor.setAttribute('x', '60');
    qAuthor.setAttribute('y', yy + 26);
    qAuthor.setAttribute('font-family', 'monospace');
    qAuthor.setAttribute('font-size', '8');
    qAuthor.setAttribute('fill', '#94a3b8');
    qAuthor.textContent = q2.author + ' \u2022 T' + q2.table;
    questionList.appendChild(qAuthor);
  }
}

function upvoteQuestion(qId) {
  // Store upvotes as flat top-level keys to avoid shallow merge destroying question data
  var upvoteKey = 'upvote:' + qId + ':' + myId;
  var patch = {};
  patch[upvoteKey] = true;
  patchMerge(Q_SECRET, patch).then(function() {
    connDot.setAttribute('fill', '#22c55e');
  }).catch(function() {
    connDot.setAttribute('fill', '#ef4444');
  });
}

function renderComments(data) {
  while (commentList.firstChild) commentList.removeChild(commentList.firstChild);
  if (!data) return;

  var comments = [];
  var keys = Object.keys(data);
  for (var i = 0; i < keys.length; i++) {
    var c = data[keys[i]];
    if (c && c.text && c.tension === currentTension) {
      comments.push(c);
    }
  }
  comments.sort(function(a, b) { return b.t - a.t; });

  // Show last 3
  var recent = comments.slice(0, 3);
  for (var j = 0; j < recent.length; j++) {
    var cm = recent[j];
    var yy = 460 + j * 32;

    var cAuthor = document.createElementNS(SVG_NS, 'text');
    cAuthor.setAttribute('x', '20');
    cAuthor.setAttribute('y', yy + 12);
    cAuthor.setAttribute('font-family', 'monospace');
    cAuthor.setAttribute('font-size', '9');
    cAuthor.setAttribute('fill', '#c9a227');
    cAuthor.textContent = cm.author;
    commentList.appendChild(cAuthor);

    var cText = document.createElementNS(SVG_NS, 'text');
    cText.setAttribute('x', '20');
    cText.setAttribute('y', yy + 26);
    cText.setAttribute('font-family', 'monospace');
    cText.setAttribute('font-size', '9');
    cText.setAttribute('fill', '#f1f5f9');
    var truncated2 = cm.text.length > 40 ? cm.text.substring(0, 40) + '...' : cm.text;
    cText.textContent = truncated2;
    commentList.appendChild(cText);
  }
}

function splitPoleLabel(name) {
  if (name.length <= 10) return [name, ''];
  var mid = Math.floor(name.length / 2);
  var spaceAfter = name.indexOf(' ', mid);
  var spaceBefore = name.lastIndexOf(' ', mid);
  var splitAt = (spaceAfter !== -1) ? spaceAfter : spaceBefore;
  if (splitAt <= 0) return [name, ''];
  return [name.substring(0, splitAt), name.substring(splitAt + 1)];
}

function updateTensionDisplay() {
  var t = TENSIONS[currentTension];
  var resultsMsg = document.getElementById('resultsMsg');
  var resultsMsg2 = document.getElementById('resultsMsg2');
  var voteSection = document.querySelector('[x="8"][y="94"]');

  if (currentPhase === 'results') {
    tensionTitle.textContent = 'Session Complete';
    tensionPoles.textContent = '';
    resultsMsg.setAttribute('display', 'inline');
    resultsMsg2.setAttribute('display', 'inline');
    waitingMsg.setAttribute('display', 'none');
    voteConfirm.setAttribute('display', 'none');
    discussPrompt.setAttribute('display', 'none');
    poleLeftLabel.textContent = '';
    poleLeftLabel2.textContent = '';
    poleRightLabel.textContent = '';
    poleRightLabel2.textContent = '';
    return;
  }

  if (currentPhase === 'checkin') {
    tensionTitle.textContent = 'Welcome';
    tensionPoles.textContent = 'Waiting for session to begin...';
    resultsMsg.setAttribute('display', 'none');
    resultsMsg2.setAttribute('display', 'none');
    waitingMsg.setAttribute('display', 'none');
    poleLeftLabel.textContent = '';
    poleLeftLabel2.textContent = '';
    poleRightLabel.textContent = '';
    poleRightLabel2.textContent = '';
    return;
  }

  resultsMsg.setAttribute('display', 'none');
  resultsMsg2.setAttribute('display', 'none');

  if (!t) return;
  tensionTitle.textContent = t.title;
  tensionPoles.textContent = t.left + ' \u25C4\u2500\u2500\u25BA ' + t.right;

  var lp = splitPoleLabel(t.left);
  poleLeftLabel.textContent = lp[0];
  poleLeftLabel2.textContent = lp[1];
  var rp = splitPoleLabel(t.right);
  poleRightLabel.textContent = rp[0];
  poleRightLabel2.textContent = rp[1];

  if (currentPhase === 'waiting') {
    waitingMsg.setAttribute('display', 'inline');
    voteConfirm.setAttribute('display', 'none');
    discussPrompt.setAttribute('display', 'none');
  } else {
    waitingMsg.setAttribute('display', 'none');
  }
}

// ============ POLLING ============
function pollAll() {
  // Poll state
  readHash(STATE_HASH).then(function(d) {
    if (d && d.val) {
      if (typeof d.val.currentTension === 'number') {
        var newTension = d.val.currentTension;
        if (newTension !== currentTension) {
          currentTension = newTension;
          myVote = 0;
          voteConfirm.setAttribute('display', 'none');
        }
      }
      if (d.val.phase) currentPhase = d.val.phase;
      if (typeof d.val.votingOpen === 'boolean') votingOpen = d.val.votingOpen;
      else votingOpen = true;
      updateTensionDisplay();
      updateVoteDisplay();
    }
    connDot.setAttribute('fill', '#22c55e');
  }).catch(function() {
    connDot.setAttribute('fill', '#ef4444');
  });

  // Poll questions
  readHash(Q_HASH).then(function(d) {
    if (d && d.val) {
      renderQuestions(d.val);
    }
  }).catch(function() {});

  // Poll comments
  readHash(C_HASH).then(function(d) {
    if (d && d.val) {
      renderComments(d.val);
    }
  }).catch(function() {});

  // Poll checkins for participant count
  readHash(CHECKIN_HASH).then(function(d) {
    if (d && d.val) {
      var count = Object.keys(d.val).length;
      footerParticipants.textContent = count + ' participant' + (count !== 1 ? 's' : '');
    }
  }).catch(function() {});
}

// ============ INIT ============
if (!checkExistingSession()) {
  // Stay on check-in mode
}
setInterval(pollAll, 2000);
